import{_ as o,c as e,m as a,a as r,t as i,a5 as n,o as p}from"./chunks/framework.DwbewbAn.js";const f=JSON.parse('{"title":"事务传播","description":"","frontmatter":{"title":"事务传播"},"headers":[],"relativePath":"doc/编程语言/后端/Java/业务框架/Spring/事务传播.md","filePath":"packages/doc/src/编程语言/后端/Java/业务框架/Spring/事务传播.md","lastUpdated":1711637456000}'),s={name:"doc/编程语言/后端/Java/业务框架/Spring/事务传播.md"},d={id:"frontmatter-title",tabindex:"-1"},l=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),h=n('<h2 id="propagation-required" tabindex="-1">Propagation.REQUIRED <a class="header-anchor" href="#propagation-required" aria-label="Permalink to &quot;Propagation.REQUIRED&quot;">​</a></h2><p>Spring默认传播行为是reuqired 当前有事务，使用当前事务 当前没有事务，创建新事物，即保证当前方法在事务中</p><h2 id="propagation-requires-new" tabindex="-1">Propagation.REQUIRES_NEW <a class="header-anchor" href="#propagation-requires-new" aria-label="Permalink to &quot;Propagation.REQUIRES_NEW&quot;">​</a></h2><p>当前没有事务，创建事务运行 当前有事务，创建新事物，即存在两个独立的事务 不管当前方法是否有事务，都会创建一个新事物，即存在两个独立事务</p><h2 id="propagation-supported" tabindex="-1">Propagation.SUPPORTED <a class="header-anchor" href="#propagation-supported" aria-label="Permalink to &quot;Propagation.SUPPORTED&quot;">​</a></h2><p>当前有事务时，使用当前事务， 当前没有事务时，无事务运行</p><h2 id="propagation-not-supports" tabindex="-1">Propagation.NOT_SUPPORTS <a class="header-anchor" href="#propagation-not-supports" aria-label="Permalink to &quot;Propagation.NOT_SUPPORTS&quot;">​</a></h2><p>当前存在事务，则挂起事务，无事务运行 当前不存在事务，直接运行 即当前方法不支持事务</p><h2 id="propagation-mandatory" tabindex="-1">Propagation.MANDATORY <a class="header-anchor" href="#propagation-mandatory" aria-label="Permalink to &quot;Propagation.MANDATORY&quot;">​</a></h2><p>当前存在事务，使用当前事务运行 当前不存在事务，抛出异常 即当前传播中必须有事务</p><h2 id="propagation-never" tabindex="-1">Propagation.NEVER <a class="header-anchor" href="#propagation-never" aria-label="Permalink to &quot;Propagation.NEVER&quot;">​</a></h2><p>当前有事务，则抛异常 当前没有事务，正常运行</p><h2 id="propagation-newsted" tabindex="-1">Propagation.NEWSTED <a class="header-anchor" href="#propagation-newsted" aria-label="Permalink to &quot;Propagation.NEWSTED&quot;">​</a></h2><p>当前有事务，在当前事务下创建一个嵌套事务，外层事务异常，内外层事务都回滚，内存事务异常，则只回滚内存事务，外层事务不会回滚 当前没有事务，则创建一个事务</p>',14);function c(t,_,g,P,u,m){return p(),e("div",null,[a("h1",d,[r(i(t.$frontmatter.title)+" ",1),l]),h])}const S=o(s,[["render",c]]);export{f as __pageData,S as default};
